#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) { return *(int*)a - *(int*)b; }

void dfs(int *arr, int sz, int start, int target, int *path, int depth, int **res, int *resSize, int *resCap) {
    if (target == 0) {
        if (*resSize == *resCap) {
            *resCap *= 2;
            *res = realloc(*res, (*resCap) * sizeof(int*));
        }
        int *comb = malloc((depth + 1) * sizeof(int)); // first element stores length
        comb[0] = depth;
        for (int i = 0; i < depth; ++i) comb[i+1] = path[i];
        (*res)[*resSize] = comb;
        (*resSize)++;
        return;
    }
    for (int i = start; i < sz; ++i) {
        if (arr[i] > target) break;
        path[depth] = arr[i];
        dfs(arr, sz, i, target - arr[i], path, depth+1, res, resSize, resCap);
    }
}

int main(){
    int T; if (scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, B; scanf("%d %d", &N, &B);
        int *a = malloc(N * sizeof(int));
        for(int i=0;i<N;++i) scanf("%d", &a[i]);
        qsort(a, N, sizeof(int), cmp);
        // remove duplicates
        int uniq[20]; int usz=0;
        for(int i=0;i<N;++i){ if(i==0||a[i]!=a[i-1]) uniq[usz++]=a[i]; }
        free(a);
        int path[20];
        int **res = malloc(4 * sizeof(int*));
        int resSize=0, resCap=4;
        dfs(uniq, usz, 0, B, path, 0, &res, &resSize, &resCap);
        printf("%d\n", resSize);
        for(int i=0;i<resSize;++i){
            int len=res[i][0];
            for(int j=1;j<=len;++j){
                if(j>1) printf(" ");
                printf("%d", res[i][j]);
            }
            printf("\n");
            free(res[i]);
        }
        free(res);
    }
    return 0;
}

