void dfs(const vector<int>& arr, int idx, int target, vector<int>& cur, vector<vector<int>>& ans){
    if(target==0){ ans.push_back(cur); return; }
    for(int i=idx;i<(int)arr.size();++i){
        if(arr[i]>target) break;
        cur.push_back(arr[i]);
        dfs(arr,i,target-arr[i],cur,ans);
        cur.pop_back();
    }
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N,B; cin>>N>>B;
        vector<int> a(N);
        for(int &x:a) cin>>x;
        sort(a.begin(),a.end());
        a.erase(unique(a.begin(),a.end()),a.end());
        vector<vector<int>> ans; vector<int> cur;
        dfs(a,0,B,cur,ans);
        cout<<ans.size()<<'\n';
        for(auto &v:ans){
            for(size_t i=0;i<v.size();++i){
                if(i) cout<<' ';
                cout<<v[i];
            }
            cout<<'\n';
        }
    }
    return 0;
}

