import java.io.*;
import java.util.*;

public class Main {
    static void dfs(int[] arr, int idx, int target, List<Integer> cur, List<List<Integer>> ans) {
        if (target == 0) {
            ans.add(new ArrayList<>(cur));
            return;
        }
        for (int i = idx; i < arr.length; i++) {
            if (arr[i] > target) break;
            cur.add(arr[i]);
            dfs(arr, i, target - arr[i], cur, ans);
            cur.remove(cur.size() - 1);
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int B = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            int[] a = new int[N];
            for (int i = 0; i < N; i++) a[i] = Integer.parseInt(st.nextToken());
            Arrays.sort(a);
            // remove duplicates
            int[] uniq = Arrays.stream(a).distinct().toArray();
            List<List<Integer>> ans = new ArrayList<>();
            dfs(uniq, 0, B, new ArrayList<>(), ans);
            out.append(ans.size()).append('\n');
            for (List<Integer> comb : ans) {
                for (int i = 0; i < comb.size(); i++) {
                    if (i > 0) out.append(' ');
                    out.append(comb.get(i));
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

