import sys

def dfs(arr, idx, target, cur, ans):
    if target == 0:
        ans.append(list(cur))
        return
    for i in range(idx, len(arr)):
        if arr[i] > target:
            break
        cur.append(arr[i])
        dfs(arr, i, target - arr[i], cur, ans)
        cur.pop()

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); B = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        a.sort()
        # remove duplicates
        uniq = []
        for x in a:
            if not uniq or uniq[-1] != x:
                uniq.append(x)
        ans = []
        dfs(uniq, 0, B, [], ans)
        out_lines.append(str(len(ans)))
        for comb in ans:
            out_lines.append(' '.join(map(str, comb)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

