let output = [];
function dfs(arr, start, target, cur, res) {
  if (target === 0) { res.push(cur.slice()); return; }
  for (let i = start; i < arr.length; i++) {
    if (arr[i] > target) break;
    cur.push(arr[i]);
    dfs(arr, i, target - arr[i], cur, res);
    cur.pop();
  }
}
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const B = Number(input[idx++]);
  let a = [];
  for (let i = 0; i < N; i++) a.push(Number(input[idx++]));
  a.sort((x, y) => x - y);
  // unique
  const uniq = [];
  for (const v of a) if (uniq.length === 0 || uniq[uniq.length - 1] !== v) uniq.push(v);
  const combos = [];
  dfs(uniq, 0, B, [], combos);
  output.push(String(combos.length));
  for (const comb of combos) output.push(comb.join(' '));
}
